export type DependencyGraph = Record<string, readonly string[]>;

export class DependencyCycleError extends Error {
  readonly cycle: string[];

  constructor(cycle: string[]) {
    super(`Dependency cycle detected: ${cycle.join(", ")}`);
    this.name = "DependencyCycleError";
    this.cycle = cycle;
  }
}

export function dependencyBatches(graph: DependencyGraph): string[][] {
  const nodes = new Set<string>();
  for (const [node, dependencies] of Object.entries(graph)) {
    nodes.add(node);
    for (const dependency of dependencies) nodes.add(dependency);
  }

  const remainingDeps = new Map<string, Set<string>>();
  const dependents = new Map<string, Set<string>>();
  for (const node of [...nodes].sort()) {
    const deps = new Set(graph[node] ?? []);
    remainingDeps.set(node, deps);
    for (const dependency of deps) {
      if (!dependents.has(dependency)) dependents.set(dependency, new Set());
      dependents.get(dependency)!.add(node);
    }
  }

  const batches: string[][] = [];
  const processed = new Set<string>();
  let ready = [...remainingDeps.entries()]
    .filter(([, deps]) => deps.size === 0)
    .map(([node]) => node)
    .sort();

  while (ready.length > 0) {
    batches.push(ready);
    const nextReady = new Set<string>();
    for (const node of ready) {
      processed.add(node);
      for (const dependent of dependents.get(node) ?? []) {
        const deps = remainingDeps.get(dependent);
        deps?.delete(node);
        if (deps?.size === 0 && !processed.has(dependent)) nextReady.add(dependent);
      }
    }
    ready = [...nextReady].sort();
  }

  if (processed.size !== nodes.size) {
    const cycle = [...nodes].filter((node) => !processed.has(node)).sort();
    throw new DependencyCycleError(cycle);
  }

  return batches;
}

import { describe, expect, it } from "vitest";
import { DependencyCycleError, dependencyBatches } from "../src/dependencyBatches";

describe("dependencyBatches", () => {
  it("batches a diamond graph", () => {
    expect(
      dependencyBatches({
        app: ["api", "ui"],
        api: ["core"],
        ui: ["core"],
        core: [],
      }),
    ).toEqual([["core"], ["api", "ui"], ["app"]]);
  });

  it("includes dependencies that are only referenced", () => {
    expect(dependencyBatches({ app: ["runtime"] })).toEqual([["runtime"], ["app"]]);
  });

  it("keeps disconnected nodes deterministic", () => {
    expect(dependencyBatches({ zebra: [], alpha: [], app: ["alpha"] })).toEqual([["alpha", "zebra"], ["app"]]);
  });

  it("throws cycle diagnostics", () => {
    expect(() => dependencyBatches({ a: ["b"], b: ["a"] })).toThrow(DependencyCycleError);
    try {
      dependencyBatches({ a: ["b"], b: ["a"] });
    } catch (error) {
      expect(error).toBeInstanceOf(DependencyCycleError);
      expect((error as DependencyCycleError).cycle).toEqual(["a", "b"]);
    }
  });
});

